1	/**
2	 * The Instrumentarium — guild tool registry apparatus.
3	 *
4	 * Scans installed tools from kit contributions and apparatus supportKits,
5	 * resolves permission-gated tool sets on demand, and serves as the single
6	 * source of truth for "what tools exist and who can use them."
7	 *
8	 * The Instrumentarium is role-agnostic — it receives an already-resolved
9	 * permissions array from the Loom and returns the matching tool set.
10	 * Role definitions and permission grants are owned by the Loom.
11	 */
12	
13	import fs from 'node:fs';
14	import path from 'node:path';
15	
16	import type {
17	  StartupContext,
18	  LoadedPlugin,
19	  LoadedKit,
20	  LoadedApparatus,
21	  Plugin,
22	} from '@shardworks/nexus-core';
23	import {
24	  guild,
25	  isLoadedKit,
26	  isLoadedApparatus,
27	} from '@shardworks/nexus-core';
28	
29	import type { ToolDefinition, ToolCaller } from './tool.ts';
30	import { isToolDefinition } from './tool.ts';
31	import { createToolsList } from './tools/tools-list.ts';
32	import { createToolsShow } from './tools/tools-show.ts';
33	import type { ToolServerHandle, ToolServerOptions, ToolsConfig } from './tool-server.ts';
34	import { startToolServer } from './tool-server.ts';
35	
36	// ── Public types ──────────────────────────────────────────────────────
37	
38	/** A resolved tool with provenance metadata. */
39	export interface ResolvedTool {
40	  /** The tool definition (name, description, params schema, handler). */
41	  definition: ToolDefinition;
42	  /** Plugin id of the kit or apparatus that contributed this tool. */
43	  pluginId: string;
44	}
45	
46	/** Options for resolving a permission-gated tool set. */
47	export interface ResolveOptions {
48	  /**
49	   * Permission grants in `plugin:level` format.
50	   * Supports wildcards: `plugin:*`, `*:level`, `*:*`.
51	   */
52	  permissions: string[];
53	  /**
54	   * When true, permissionless tools are excluded unless the role grants
55	   * `plugin:*` or `*:*` for the tool's plugin. When false (default),
56	   * permissionless tools are included unconditionally.
57	   */
58	  strict?: boolean;
59	  /** Filter by invocation caller. Tools with no callableBy pass all callers. */
60	  caller?: ToolCaller;
61	}
62	
63	/** The Instrumentarium's public API, exposed via `provides`. */
64	export interface InstrumentariumApi {
65	  /**
66	   * Resolve the tool set for a given set of permissions.
67	   *
68	   * Evaluates each registered tool against the permission grants:
69	   * - Tools with a `permission` field: included if any grant matches
70	   * - Permissionless tools: always included (default) or gated by `strict`
71	   * - Caller filtering applied last
72	   */
73	  resolve(options: ResolveOptions): ResolvedTool[];
74	
75	  /**
76	   * Find a single tool by name. Returns null if not installed.
77	   */
78	  find(name: string): ResolvedTool | null;
79	
80	  /**
81	   * List all installed tools, regardless of permissions.
82	   */
83	  list(): ResolvedTool[];
84	
85	  /**
86	   * Start the Tool HTTP server.
87	   *
88	   * Serves all registered tools over HTTP with session-scoped authorization.
89	   * Binds to 127.0.0.1 on the configured port (guild.json tools.serverPort
90	   * or opts.port, defaulting to 7471).
91	   *
92	   * Returns a handle for lifecycle management.
93	   */
94	  startToolServer(opts?: ToolServerOptions): Promise<ToolServerHandle>;
95	}
96	
97	// ── Permission matching ──────────────────────────────────────────────
98	
99	/** A parsed permission grant. */
100	interface ParsedGrant {
101	  plugin: string;
102	  level: string;
103	}
104	
105	/** Parse a grant string like "plugin:level" into its components. */
106	function parseGrant(grant: string): ParsedGrant | null {
107	  const colonIdx = grant.indexOf(':');
108	  if (colonIdx === -1) return null;
109	  return {
110	    plugin: grant.slice(0, colonIdx),
111	    level: grant.slice(colonIdx + 1),
112	  };
113	}
114	
115	/**
116	 * Check if a tool with the given permission level from the given plugin
117	 * is matched by any of the parsed grants.
118	 */
119	function matchesPermission(
120	  pluginId: string,
121	  permission: string,
122	  grants: ParsedGrant[],
123	): boolean {
124	  for (const grant of grants) {
125	    // Exact match: plugin:level
126	    if (grant.plugin === pluginId && grant.level === permission) return true;
127	    // Plugin wildcard: plugin:*
128	    if (grant.plugin === pluginId && grant.level === '*') return true;
129	    // Level wildcard: *:level
130	    if (grant.plugin === '*' && grant.level === permission) return true;
131	    // Superuser: *:*
132	    if (grant.plugin === '*' && grant.level === '*') return true;
133	  }
134	  return false;
135	}
136	
137	/**
138	 * Check if a permissionless tool from the given plugin should be included
139	 * in strict mode. Only `plugin:*` or `*:*` opts in permissionless tools.
140	 */
141	function strictAllowsPermissionless(
142	  pluginId: string,
143	  grants: ParsedGrant[],
144	): boolean {
145	  for (const grant of grants) {
146	    if (grant.plugin === pluginId && grant.level === '*') return true;
147	    if (grant.plugin === '*' && grant.level === '*') return true;
148	  }
149	  return false;
150	}
151	
152	// ── Implementation ────────────────────────────────────────────────────
153	
154	/**
155	 * The tool registry — accumulates tools from plugin contributions
156	 * and resolves permission-gated tool sets.
157	 */
158	class ToolRegistry {
159	  /** Map from tool name → ResolvedTool. Last-write-wins for duplicates. */
160	  private readonly tools = new Map<string, ResolvedTool>();
161	  /** Guild root path — set at startup, used for instructionsFile resolution. */
162	  private guildHome = '';
163	
164	  /** Set the guild root path for instructionsFile resolution. */
165	  setHome(home: string): void {
166	    this.guildHome = home;
167	  }
168	
169	  /** Register all tools from a loaded plugin. */
170	  register(plugin: LoadedPlugin): void {
171	    const pluginId = plugin.id;
172	    const packageName = plugin.packageName;
173	
174	    if (isLoadedKit(plugin)) {
175	      this.registerToolsFromKit(pluginId, packageName, plugin.kit);
176	    } else if (isLoadedApparatus(plugin)) {
177	      if (plugin.apparatus.supportKit) {
178	        this.registerToolsFromKit(pluginId, packageName, plugin.apparatus.supportKit);
179	      }
180	    }
181	  }
182	
183	  /** Extract and register tools from a kit (or supportKit) contribution. */
184	  private registerToolsFromKit(
185	    pluginId: string,
186	    packageName: string,
187	    kit: Record<string, unknown>,
188	  ): void {
189	    const rawTools = kit.tools;
190	    if (!Array.isArray(rawTools)) return;
191	
192	    for (const t of rawTools) {
193	      if (isToolDefinition(t)) {
194	        this.validatePermission(t, pluginId);
195	        const definition = this.preloadInstructions(t, packageName);
196	        this.tools.set(definition.name, { definition, pluginId });
197	      }
198	    }
199	  }
200	
201	  /**
202	   * Pre-load instructionsFile into instructions text.
203	   *
204	   * If the tool has an `instructionsFile`, resolve it relative to the
205	   * package root in node_modules, read the file, and return a copy with
206	   * `instructions` set to the file content and `instructionsFile` cleared.
207	   *
208	   * Tools with inline `instructions` or neither field are returned as-is.
209	   */
210	  preloadInstructions(
211	    tool: ToolDefinition,
212	    packageName: string,
213	  ): ToolDefinition {
214	    if (!tool.instructionsFile) return tool;
215	
216	    const packageDir = path.join(this.guildHome, 'node_modules', packageName);
217	    const filePath = path.join(packageDir, tool.instructionsFile);
218	
219	    try {
220	      const content = fs.readFileSync(filePath, 'utf-8');
221	      // Return a mutated copy — instructionsFile consumed, instructions set
222	      const { instructionsFile: _, ...rest } = tool;
223	      return { ...rest, instructions: content } as ToolDefinition;
224	    } catch {
225	      console.warn(
226	        `[instrumentarium] Could not read instructions file for tool "${tool.name}": ${filePath}`,
227	      );
228	      // Return tool without instructions — don't block registration
229	      const { instructionsFile: _, ...rest } = tool;
230	      return rest as ToolDefinition;
231	    }
232	  }
233	
234	  /**
235	   * Validate that a tool's permission string uses the bare-level convention.
236	   *
237	   * Permission strings must be bare levels like 'read', 'write', 'delete', 'admin'.
238	   * The plugin id is attached automatically by the grant-matching system.
239	   * A colon in the permission string indicates the non-conforming `plugin:level`
240	   * form, which causes silent resolution failures.
241	   */
242	  private validatePermission(definition: ToolDefinition, pluginId: string): void {
243	    if (definition.permission && definition.permission.includes(':')) {
244	      throw new Error(
245	        `Tool "${definition.name}" (plugin "${pluginId}") declares permission "${definition.permission}" ` +
246	        `which contains a colon. Permission strings are bare levels (e.g. "read", "write"); ` +
247	        `the plugin id is attached automatically. See packages/plugins/tools/src/tool.ts docstring.`,
248	      );
249	    }
250	  }
251	
252	  /** Register a single tool definition directly (for self-contributed tools). */
253	  registerTool(definition: ToolDefinition, pluginId: string): void {
254	    this.validatePermission(definition, pluginId);
255	    this.tools.set(definition.name, { definition, pluginId });
256	  }
257	
258	  /** Find a tool by name. */
259	  find(name: string): ResolvedTool | null {
260	    return this.tools.get(name) ?? null;
261	  }
262	
263	  /** List all installed tools. */
264	  list(): ResolvedTool[] {
265	    return [...this.tools.values()];
266	  }
267	
268	  /**
269	   * Resolve a permission-gated tool set.
270	   *
271	   * 1. Parse each grant into (plugin, level) pairs
272	   * 2. For each registered tool:
273	   *    a. If tool has no permission:
274	   *       - If NOT strict → include
275	   *       - If strict → include only if grants contain <tool's plugin>:* or *:*
276	   *    b. If tool has a permission:
277	   *       - Match against grants: exact, plugin wildcard, level wildcard, or superuser
278	   *       - Include if any grant matches
279	   * 3. Filter by caller (callableBy)
280	   */
281	  resolve(options: ResolveOptions): ResolvedTool[] {
282	    const grants = options.permissions
283	      .map(parseGrant)
284	      .filter((g): g is ParsedGrant => g !== null);
285	    const strict = options.strict ?? false;
286	
287	    const result: ResolvedTool[] = [];
288	
289	    for (const resolved of this.tools.values()) {
290	      const { definition, pluginId } = resolved;
291	      const permission = definition.permission;
292	
293	      // Permission check
294	      if (permission === undefined) {
295	        // Permissionless tool
296	        if (strict && !strictAllowsPermissionless(pluginId, grants)) {
297	          continue;
298	        }
299	        // In default mode, permissionless tools are always included
300	      } else {
301	        // Tool has a permission — must match against grants
302	        if (!matchesPermission(pluginId, permission, grants)) {
303	          continue;
304	        }
305	      }
306	
307	      // Caller filter
308	      if (
309	        options.caller &&
310	        definition.callableBy &&
311	        !definition.callableBy.includes(options.caller)
312	      ) {
313	        continue;
314	      }
315	
316	      result.push(resolved);
317	    }
318	
319	    return result;
320	  }
321	}
322	
323	// ── Apparatus factory ─────────────────────────────────────────────────
324	
325	/**
326	 * Create the Instrumentarium apparatus plugin.
327	 *
328	 * Returns a Plugin with:
329	 * - `consumes: ['tools']` — scans kit/supportKit contributions
330	 * - `provides: InstrumentariumApi` — the tool registry API
331	 */
332	export function createInstrumentarium(): Plugin {
333	  const registry = new ToolRegistry();
334	
335	  const api: InstrumentariumApi = {
336	    resolve(options: ResolveOptions): ResolvedTool[] {
337	      return registry.resolve(options);
338	    },
339	
340	    find(name: string): ResolvedTool | null {
341	      return registry.find(name);
342	    },
343	
344	    list(): ResolvedTool[] {
345	      return registry.list();
346	    },
347	
348	    async startToolServer(opts?: ToolServerOptions): Promise<ToolServerHandle> {
349	      const g = guild();
350	      const toolsConfig = g.config<ToolsConfig>('tools');
351	      const port = opts?.port ?? toolsConfig?.serverPort ?? 7471;
352	      return startToolServer(api, port, opts?.authorize);
353	    },
354	  };
355	
356	  // Introspection tools use a lazy getter so they can query the registry
357	  // after all plugins have registered their tools at startup.
358	  const getApi = () => api;
359	  const toolsList = createToolsList(getApi);
360	  const toolsShow = createToolsShow(getApi);
361	
362	  return {
363	    apparatus: {
364	      requires: [],
365	      consumes: ['tools'],
366	      provides: api,
367	
368	      supportKit: {
369	        tools: [toolsList, toolsShow],
370	      },
371	
372	      start(ctx: StartupContext): void {
373	        const g = guild();
374	        registry.setHome(g.home);
375	
376	        // Register all tool contributions (standalone kits + apparatus supportKits)
377	        // via the Wire-phase ctx.kits('tools') snapshot.
378	        for (const entry of ctx.kits('tools')) {
379	          const rawTools = entry.value;
380	          if (!Array.isArray(rawTools)) continue;
381	          for (const t of rawTools) {
382	            if (isToolDefinition(t)) {
383	              const definition = registry.preloadInstructions(t, entry.packageName);
384	              registry.registerTool(definition, entry.pluginId);
385	            }
386	          }
387	        }
388	      },
389	    },
390	  };
391	}
