77	// ── Retry constants ─────────────────────────────────────────────────────
78	
79	const RETRY_INITIAL_DELAY_MS = 1_000;
80	const RETRY_MAX_DELAY_MS = 8_000;
81	const RETRY_TIMEOUT_MS = 60_000;
82	const RETRYABLE_CODES = new Set(['ECONNREFUSED', 'ECONNRESET', 'ETIMEDOUT']);
83	
84	/**
85	 * Walk an error's cause chain looking for a retryable error code.
86	 * Returns the first retryable code found, or null if none.
87	 * Caps traversal depth to prevent infinite loops from circular cause chains.
88	 */
89	export function findRetryableCode(err: unknown, maxDepth: number = 5): string | null {
90	  let current: unknown = err;
91	  for (let i = 0; i < maxDepth && current != null; i++) {
92	    const code = (current as NodeJS.ErrnoException).code;
93	    if (code && RETRYABLE_CODES.has(code)) {
94	      return code;
95	    }
96	    current = (current as Error).cause;
97	  }
98	  return null;
99	}
