112	/**
113	 * Read the babysitter config from stdin.
114	 *
115	 * Reads stdin to completion, parses the JSON, and validates required fields.
116	 * The spawning process writes config and closes the write end.
117	 */
118	export async function readConfigFromStdin(
119	  stream: NodeJS.ReadableStream = process.stdin,
120	): Promise<BabysitterConfig> {
121	  const chunks: Buffer[] = [];
122	
123	  for await (const chunk of stream) {
124	    chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk as string));
125	  }
126	
127	  const raw = Buffer.concat(chunks).toString('utf-8');
128	  if (!raw.trim()) {
129	    throw new Error('Empty config received on stdin');
130	  }
131	
132	  let parsed: unknown;
133	  try {
134	    parsed = JSON.parse(raw);
135	  } catch {
136	    throw new Error(`Invalid JSON config on stdin: ${raw.slice(0, 200)}`);
137	  }
138	
139	  const config = parsed as BabysitterConfig;
140	
141	  // Validate required fields
142	  const required: (keyof BabysitterConfig)[] = [
143	    'sessionId', 'guildToolUrl', 'dbPath', 'claudeArgs',
144	    'cwd', 'env', 'prompt', 'tools', 'startedAt', 'provider',
145	  ];
146	  for (const field of required) {
147	    if (config[field] === undefined || config[field] === null) {
148	      throw new Error(`Missing required config field: ${field}`);
149	    }
150	  }
151	
152	  return config;
153	}
