155	// ── HTTP retry helper ───────────────────────────────────────────────────
156	
157	/**
158	 * Call a guild HTTP API endpoint with exponential backoff retry.
159	 *
160	 * Retries on connection errors (ECONNREFUSED, ECONNRESET, ETIMEDOUT).
161	 * Returns the parsed JSON response on success.
162	 * Throws after RETRY_TIMEOUT_MS of retrying.
163	 */
164	/**
165	 * Encode a params object as a query string for GET requests.
166	 *
167	 * Scalars (string/number/boolean) become their string form. Arrays and
168	 * objects are JSON-encoded so the tool-server can still parse them after
169	 * its param coercion pass (though read-tools generally take scalar
170	 * inputs). null/undefined values are skipped.
171	 */
172	function encodeParamsAsQuery(params: unknown): string {
173	  if (params == null || typeof params !== 'object') return '';
174	  const usp = new URLSearchParams();
175	  for (const [key, value] of Object.entries(params as Record<string, unknown>)) {
176	    if (value == null) continue;
177	    if (typeof value === 'string') {
178	      usp.set(key, value);
179	    } else if (typeof value === 'number' || typeof value === 'boolean') {
180	      usp.set(key, String(value));
181	    } else {
182	      usp.set(key, JSON.stringify(value));
183	    }
184	  }
185	  const s = usp.toString();
186	  return s.length > 0 ? `?${s}` : '';
187	}
188	
189	export async function callGuildHttpApi(
190	  url: string,
191	  sessionId: string,
192	  body: unknown,
193	  timeoutMs: number = RETRY_TIMEOUT_MS,
194	  method: 'GET' | 'POST' | 'DELETE' = 'POST',
195	): Promise<unknown> {
196	  const startTime = Date.now();
197	  let delay = RETRY_INITIAL_DELAY_MS;
198	  let lastError: Error | undefined;
199	
200	  // GET can't carry a body — encode params as query string instead.
201	  const targetUrl = method === 'GET' ? `${url}${encodeParamsAsQuery(body)}` : url;
202	  const requestBody = method === 'GET' ? undefined : JSON.stringify(body);
203	
204	  while (Date.now() - startTime < timeoutMs) {
205	    try {
206	      const response = await fetch(targetUrl, {
207	        method,
208	        headers: {
209	          'Content-Type': 'application/json',
210	          'X-Session-Id': sessionId,
211	        },
212	        ...(requestBody !== undefined ? { body: requestBody } : {}),
213	      });
214	
215	      if (!response.ok) {
216	        const text = await response.text().catch(() => '');
217	        throw new Error(`HTTP ${response.status}: ${text.slice(0, 500)}`);
218	      }
219	
220	      return await response.json();
221	    } catch (err) {
222	      lastError = err instanceof Error ? err : new Error(String(err));
223	
224	      // Check if the error is retryable (connection-level error in the cause chain)
225	      const isRetryable = findRetryableCode(err) !== null;
226	
227	      if (!isRetryable) {
228	        throw lastError;
229	      }
230	
231	      // Wait before retrying
232	      const remaining = timeoutMs - (Date.now() - startTime);
233	      if (remaining <= 0) break;
234	
235	      await new Promise((resolve) => setTimeout(resolve, Math.min(delay, remaining)));
236	      delay = Math.min(delay * 2, RETRY_MAX_DELAY_MS);
237	    }
238	  }
239	
240	  throw new Error(
241	    `Guild HTTP API unreachable after ${timeoutMs}ms: ${lastError?.message ?? 'unknown error'}`,
242	  );
243	}
