247	/**
248	 * Write a payload to the Dead Letter Queue.
249	 *
250	 * Creates the DLQ directory if it doesn't exist. Writes the payload as
251	 * pretty-printed JSON. Used as a fallback when the guild HTTP API is
252	 * unreachable for lifecycle calls.
253	 */
254	export function writeToDlq(cwd: string, filename: string, payload: unknown): void {
255	  const dlqDir = path.join(cwd, '.nexus', 'dlq');
256	  fs.mkdirSync(dlqDir, { recursive: true });
257	  fs.writeFileSync(
258	    path.join(dlqDir, filename),
259	    JSON.stringify(payload, null, 2),
260	  );
261	}
