263	// ── MCP proxy server ────────────────────────────────────────────────────
264	
265	/**
266	 * Create an MCP/SSE HTTP server that proxies tool calls to the guild.
267	 *
268	 * For each tool in the config, registers an MCP tool whose handler
269	 * forwards the call to the guild's Tool HTTP API via HTTP POST.
270	 *
271	 * Uses the low-level MCP Server class to register tools with raw
272	 * JSON Schema (the serialized params from the config).
273	 */
274	export async function createProxyMcpHttpServer(
275	  tools: SerializedTool[],
276	  guildToolUrl: string,
277	  sessionId: string,
278	): Promise<McpProxyHandle> {
279	  const server = new Server(
280	    { name: 'nexus-guild-proxy', version: '0.0.0' },
281	    { capabilities: { tools: {} } },
282	  );
283	
284	  // Register tools/list handler — advertises all tools with their JSON Schema.
285	  server.setRequestHandler(ListToolsRequestSchema, async () => ({
286	    tools: tools.map((t) => ({
287	      name: t.name,
288	      description: t.description,
289	      inputSchema: {
290	        type: 'object' as const,
291	        ...t.params,
292	      },
293	    })),
294	  }));
295	
296	  // Build a name → HTTP method lookup so the proxy can route each call to
297	  // the correct verb (read tools are GET-only on the tool server; POSTing
298	  // to them 404s).
299	  const toolMethods = new Map<string, 'GET' | 'POST' | 'DELETE'>();
300	  for (const t of tools) {
301	    toolMethods.set(t.name, t.method);
302	  }
303	
304	  // Register tools/call handler — proxies each call to the guild HTTP API.
305	  server.setRequestHandler(CallToolRequestSchema, async (request) => {
306	    const toolName = request.params.name;
307	    const params = request.params.arguments ?? {};
308	
309	    const route = toolNameToRoute(toolName);
310	    const url = `${guildToolUrl}${route}`;
311	    const method = toolMethods.get(toolName) ?? 'POST';
312	
313	    try {
314	      const result = await callGuildHttpApi(url, sessionId, params, undefined, method);
315	      const text = typeof result === 'string' ? result : JSON.stringify(result, null, 2);
316	      return {
317	        content: [{ type: 'text' as const, text }],
318	      };
319	    } catch (err) {
320	      const message = err instanceof Error ? err.message : String(err);
321	      return {
322	        content: [{ type: 'text' as const, text: `Error: ${message}` }],
323	        isError: true,
324	      };
325	    }
326	  });
327	
328	  // Wrap in HTTP server with SSE transport (same pattern as mcp-server.ts).
329	  // Promise-gate: POST /message waits for the SSE transport to be fully connected,
330	  // eliminating the race where a POST arrives before GET /sse completes.
331	  let resolveTransport!: (t: SSEServerTransport) => void;
332	  let rejectTransport!: (err: Error) => void;
333	  const transportReady = new Promise<SSEServerTransport>((resolve, reject) => {
334	    resolveTransport = resolve;
335	    rejectTransport = reject;
336	  });
337	
338	  // Direct reference for close() — null until connected.
339	  let transport: SSEServerTransport | null = null;
340	
341	  const httpServer = http.createServer(async (req, res) => {
342	    try {
343	      if (req.method === 'GET' && req.url === '/sse') {
344	        const t = new SSEServerTransport('/message', res);
345	        try {
346	          await server.connect(t);
347	          transport = t;
348	          resolveTransport(t);
349	        } catch (err) {
350	          rejectTransport(err instanceof Error ? err : new Error(String(err)));
351	          throw err;
352	        }
353	      } else if (req.method === 'POST' && req.url?.startsWith('/message')) {
354	        if (!transport) {
355	          process.stderr.write(`[babysitter] POST /message arrived before SSE transport ready — waiting\n`);
356	        }
357	        let t: SSEServerTransport;
358	        try {
359	          t = await transportReady;
360	        } catch {
361	          res.writeHead(503).end('SSE transport failed to initialize');
362	          return;
363	        }
364	        await t.handlePostMessage(req, res);
365	      } else {
366	        res.writeHead(404).end('Not found');
367	      }
368	    } catch {
369	      if (!res.headersSent) {
370	        res.writeHead(500).end('Internal Server Error');
371	      }
372	    }
373	  });
374	
375	  await new Promise<void>((resolve) => {
376	    httpServer.listen(0, '127.0.0.1', resolve);
377	  });
378	
379	  const addr = httpServer.address();
380	  if (!addr || typeof addr === 'string') {
381	    throw new Error('Failed to get MCP proxy server address');
382	  }
383	
384	  const url = `http://127.0.0.1:${addr.port}/sse`;
385	  process.stderr.write(`[babysitter] MCP proxy server listening on port ${addr.port}\n`);
386	
387	  return {
388	    url,
389	    async close() {
390	      if (transport) {
391	        await transport.close();
392	      }
393	      await new Promise<void>((resolve, reject) => {
394	        httpServer.close((err) => (err ? reject(err) : resolve()));
395	      });
396	    },
397	  };
398	}
