402	/** Minimal interface for the SQLite database used by the babysitter. */
403	export interface TranscriptDb {
404	  /** Write a transcript entry (id, content JSON). */
405	  writeTranscript(sessionId: string, content: string): void;
406	  /** Close the database connection. */
407	  close(): void;
408	}
