410	/**
411	 * Open the guild's SQLite database for transcript streaming.
412	 *
413	 * Creates the database file and table if they don't exist.
414	 * Enables WAL mode for concurrent read access by other processes
415	 * (Oculus, CLI queries, other agents).
416	 *
417	 * Uses dynamic import() to load better-sqlite3 at runtime. This avoids
418	 * requiring the native module at import time (beneficial for type-checking
419	 * and testing).
420	 */
421	export async function openTranscriptDb(dbPath: string): Promise<TranscriptDb> {
422	  const { default: Database } = await import('better-sqlite3');
423	  return initTranscriptDb(Database, dbPath);
424	}
425	
426	/**
427	 * Initialize a TranscriptDb from a Database constructor.
428	 *
429	 * Shared logic between openTranscriptDb() and test injection.
430	 * Exported for testing — allows injecting a mock Database constructor.
431	 */
432	export function initTranscriptDb(
433	  DatabaseConstructor: new (path: string) => {
434	    pragma(stmt: string): unknown;
435	    prepare(sql: string): { run(...params: unknown[]): void };
436	    exec(sql: string): void;
437	    close(): void;
438	  },
439	  dbPath: string,
440	): TranscriptDb {
441	  const raw = new DatabaseConstructor(dbPath);
442	  raw.pragma('journal_mode = WAL');
443	  raw.exec(`
444	    CREATE TABLE IF NOT EXISTS books_animator_transcripts (
445	      id      TEXT PRIMARY KEY,
446	      content TEXT NOT NULL
447	    )
448	  `);
449	  const stmt = raw.prepare(
450	    'INSERT OR REPLACE INTO books_animator_transcripts (id, content) VALUES (?, ?)',
451	  );
452	
453	  return {
454	    writeTranscript(sessionId: string, content: string) {
455	      stmt.run(sessionId, content);
456	    },
457	    close() {
458	      raw.close();
459	    },
460	  };
461	}
462	
463	/**
464	 * Write the current transcript to SQLite.
465	 */
466	export function writeTranscript(
467	  db: TranscriptDb,
468	  sessionId: string,
469	  messages: Record<string, unknown>[],
470	): void {
471	  const content = JSON.stringify({ id: sessionId, messages });
472	  db.writeTranscript(sessionId, content);
473	}
