541	// ── Main babysitter function ────────────────────────────────────────────
542	
543	/**
544	 * Run the session babysitter.
545	 *
546	 * This is the main orchestration function. It:
547	 * 1. Opens SQLite for transcript streaming
548	 * 2. Starts the MCP proxy server
549	 * 3. Prepares session files (tmpDir, system prompt, mcp-config)
550	 * 4. Spawns claude
551	 * 5. Reports "running" status
552	 * 6. Streams transcript to SQLite
553	 * 7. Reports result on exit
554	 * 8. Cleans up
555	 */
556	export async function runBabysitter(
557	  config: BabysitterConfig,
558	  deps?: {
559	    /** Injected TranscriptDb for testing (avoids loading better-sqlite3). */
560	    db?: TranscriptDb;
561	    /** Override spawn for testing. */
562	    spawnFn?: typeof spawn;
563	    /** Override retry timeout for testing (default: 60_000ms). */
564	    retryTimeoutMs?: number;
565	  },
566	): Promise<void> {
567	  const spawnFn = deps?.spawnFn ?? spawn;
568	  const retryTimeoutMs = deps?.retryTimeoutMs;
569	  let db: TranscriptDb | null = null;
570	  let mcpHandle: McpProxyHandle | null = null;
571	  let tmpDir: string | null = null;
572	  let claudeProc: ChildProcess | null = null;
573	
574	  try {
575	    // 1. Open SQLite
576	    db = deps?.db ?? await openTranscriptDb(config.dbPath);
577	
578	    // 2. Start MCP proxy server
579	    mcpHandle = await createProxyMcpHttpServer(
580	      config.tools,
581	      config.guildToolUrl,
582	      config.sessionId,
583	    );
584	
585	    // 3. Prepare session files
586	    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'nsg-babysitter-'));
587	
588	    const args = [...config.claudeArgs];
589	
590	    // Write system prompt if present in args (already handled by claudeArgs)
591	    // Write mcp-config pointing to the babysitter's MCP proxy server
592	    const mcpConfig = {
593	      mcpServers: {
594	        'nexus-guild': {
595	          type: 'sse',
596	          url: mcpHandle.url,
597	        },
598	      },
599	    };
600	    const mcpConfigPath = path.join(tmpDir, 'mcp-config.json');
601	    fs.writeFileSync(mcpConfigPath, JSON.stringify(mcpConfig));
602	    args.push('--mcp-config', mcpConfigPath, '--strict-mcp-config');
603	
604	    // Add autonomous mode flags
605	    args.push(
606	      '--print', '-',
607	      '--output-format', 'stream-json',
608	      '--verbose',
609	    );
610	
611	    // 4. Spawn claude
612	    claudeProc = spawnFn('claude', args, {
613	      cwd: config.cwd,
614	      stdio: ['pipe', 'pipe', 'inherit'],
615	      env: { ...process.env, ...config.env },
616	    });
617	
618	    // Pipe prompt to claude's stdin, then close
619	    if (config.prompt) {
620	      claudeProc.stdin!.write(config.prompt);
621	    }
622	    claudeProc.stdin!.end();
623	
624	    // 5. Report "running" status (don't await — fire and forget with retry)
625	    const cancelHandle = { kind: 'local-pgid' as const, pgid: process.pid };
626	    const runningPromise = reportRunning(config, cancelHandle, retryTimeoutMs).catch((err) => {
627	      process.stderr.write(`[babysitter] Failed to report running: ${err}\n`);
628	    });
629	
630	    // 5b. Heartbeat timer — sends liveness signal every 30s after ready report.
631	    const HEARTBEAT_INTERVAL_MS = 30_000;
632	    const HEARTBEAT_TIMEOUT_MS = 10_000;
633	    let heartbeatTimer: ReturnType<typeof setTimeout> | null = null;
634	
635	    function scheduleHeartbeat() {
636	      heartbeatTimer = setTimeout(async () => {
637	        const route = toolNameToRoute('session-heartbeat');
638	        const hbUrl = `${config.guildToolUrl}${route}`;
639	        try {
640	          await callGuildHttpApi(hbUrl, config.sessionId, { sessionId: config.sessionId }, HEARTBEAT_TIMEOUT_MS);
641	        } catch {
642	          // Dropped — next heartbeat in 30s. Staleness threshold (90s) tolerates this.
643	        }
644	        scheduleHeartbeat();
645	      }, HEARTBEAT_INTERVAL_MS);
646	    }
647	
648	    // Start heartbeat after running report completes
649	    runningPromise.then(() => scheduleHeartbeat());
650	
651	    // 5c. SIGTERM handler — sets cancelled flag and propagates to claude.
652	    let cancelledBySignal = false;
653	
654	    const onSigterm = () => {
655	      cancelledBySignal = true;
656	      // Stop heartbeat timer
657	      if (heartbeatTimer) {
658	        clearTimeout(heartbeatTimer);
659	        heartbeatTimer = null;
660	      }
661	      // Propagate SIGTERM to the claude process
662	      if (claudeProc && claudeProc.pid && !claudeProc.killed) {
663	        try {
664	          claudeProc.kill('SIGTERM');
665	        } catch { /* already dead */ }
666	      }
667	      // The normal claude exit path will run, check cancelledBySignal,
668	      // and report status 'cancelled' instead of computing from exit code.
669	    };
670	
671	    process.on('SIGTERM', onSigterm);
672	
673	    // 6. Consume stdout, stream transcript
674	    const acc: {
675	      transcript: Record<string, unknown>[];
676	      costUsd?: number;
677	      tokenUsage?: StreamJsonResult['tokenUsage'];
678	      providerSessionId?: string;
679	    } = { transcript: [] };
680	
681	    let buffer = '';
682	
683	    claudeProc.stdout!.on('data', (chunk: Buffer) => {
684	      buffer += chunk.toString();
685	      const prevLength = acc.transcript.length;
686	      buffer = processNdjsonBuffer(buffer, (msg) => {
687	        parseStreamJsonMessage(msg, acc);
688	      });
689	
690	      // Write transcript to SQLite if new messages were added
691	      if (acc.transcript.length > prevLength && db) {
692	        writeTranscript(db, config.sessionId, acc.transcript);
693	      }
694	    });
695	
696	    // 7. Wait for claude to exit
697	    const { code: exitCode, signal: exitSignal } = await new Promise<{ code: number; signal: string | undefined }>((resolve, reject) => {
698	      claudeProc!.on('error', (err) => {
699	        reject(new Error(`Failed to spawn claude: ${err.message}`));
700	      });
701	      claudeProc!.on('close', (code, signal) => {
702	        resolve({ code: code ?? 1, signal: signal ?? undefined });
703	      });
704	    });
705	
706	    // Stop heartbeat before terminal report
707	    if (heartbeatTimer) {
708	      clearTimeout(heartbeatTimer);
709	      heartbeatTimer = null;
710	    }
711	
712	    // Clean up SIGTERM handler
713	    process.removeListener('SIGTERM', onSigterm);
714	
715	    // Ensure running report completed before recording result
716	    await runningPromise;
717	
718	    // Build result
719	    const result: StreamJsonResult = {
720	      exitCode,
721	      transcript: acc.transcript,
722	      costUsd: acc.costUsd,
723	      tokenUsage: acc.tokenUsage,
724	      providerSessionId: acc.providerSessionId,
725	      signal: exitSignal,
726	    };
727	
728	    // 8. Report result
729	    await reportResult(config, result, acc.transcript, retryTimeoutMs, cancelledBySignal ? 'cancelled' : undefined);
730	  } catch (err) {
731	    // Top-level error: attempt to report failure
732	    const message = err instanceof Error ? err.message : String(err);
733	
734	    try {
735	      const route = toolNameToRoute('session-record');
736	      const url = `${config.guildToolUrl}${route}`;
737	      await callGuildHttpApi(url, config.sessionId, {
738	        sessionId: config.sessionId,
739	        status: 'failed',
740	        exitCode: 1,
741	        error: message,
742	      }, retryTimeoutMs);
743	    } catch {
744	      writeToDlq(config.cwd, `${config.sessionId}.json`, {
745	        sessionId: config.sessionId,
746	        status: 'failed',
747	        exitCode: 1,
748	        error: message,
749	      });
750	    }
751	
752	    throw err;
753	  } finally {
754	    // 9. Cleanup
755	    process.removeAllListeners('SIGTERM');
756	    await mcpHandle?.close().catch(() => {});
757	    db?.close();
758	    if (tmpDir) {
759	      fs.rmSync(tmpDir, { recursive: true, force: true });
760	    }
761	    if (config.systemPromptTmpDir) {
762	      fs.rmSync(config.systemPromptTmpDir, { recursive: true, force: true });
763	    }
764	  }
765	}
766	
767	// ── Entry point ─────────────────────────────────────────────────────────
768	
769	/**
770	 * Script entry point — reads config from stdin and runs the babysitter.
771	 *
772	 * Only executes when this file is run directly (not when imported).
773	 */
774	async function main(): Promise<void> {
775	  try {
776	    const config = await readConfigFromStdin();
777	    await runBabysitter(config);
778	    process.exit(0);
779	  } catch (err) {
780	    process.stderr.write(
781	      `[babysitter] Fatal error: ${err instanceof Error ? err.message : String(err)}\n`,
782	    );
783	    process.exit(1);
784	  }
785	}
786	
787	// Check if this module is the entry point
788	const isEntryPoint = process.argv[1] &&
789	  (process.argv[1] === fileURLToPath(import.meta.url) ||
790	   path.basename(process.argv[1]) === 'babysitter.js' ||
791	   path.basename(process.argv[1]) === 'babysitter.ts');
792	
793	if (isEntryPoint) {
794	  main();
795	}
