173	function encodeParamsAsQuery(params: unknown): string {
174	  if (params == null || typeof params !== 'object') return '';
175	  const usp = new URLSearchParams();
176	  for (const [key, value] of Object.entries(params as Record<string, unknown>)) {
177	    if (value == null) continue;
178	    if (typeof value === 'string') {
179	      usp.set(key, value);
180	    } else if (typeof value === 'number' || typeof value === 'boolean') {
181	      usp.set(key, String(value));
182	    } else {
183	      usp.set(key, JSON.stringify(value));
184	    }
185	  }
186	  const s = usp.toString();
187	  return s.length > 0 ? `?${s}` : '';
